const amqp = require('amqplib');
const db = require('./db'); // assuming a 'db' module exports a database connection function
const { exec } = require('child_process');

async function processMessage(ch, method, properties, body) {
    const messageData = JSON.parse(body.toString());

    switch (messageData.type) {
        case 'CREATE_USER':
            await db.createUser(messageData.data);
            break;
        case 'DELETE_USER':
            await db.deleteUser(messageData.data.userId);
            break;
        default:
            console.log(`Unknown message type: ${messageData.type}`);
            return;
    }

    ch.ack(method.properties.correlationId);
}

async function main() {
    try {
        const connection = await amqp.connect('amqp://localhost');
        const channel = await connection.createChannel();

        await channel.assertQueue('my_queue', { durable: true });

        console.log(" [*] Waiting for messages in my_queue. To exit press CTRL+C");

        channel.consume('my_queue', async (msg) => {
            if (msg !== null) {
                processMessage(channel, msg.properties, msg.content);
            }
        });
    } catch (err) {
        console.error(err);
    }
}

process.on('SIGINT', () => {
    // send message to RabbitMQ for graceful shutdown
});

